126→            class:annotated
127→            class:near-cursor={nearCursor && !selected}
128→            aria-pressed={selected}
129→            onclick={(event) => handleSelect(event, change)}
130→          >
131→            <div class="change-row-top">
132→              <div class="change-title">
133→                <span class="marker" class:deletion={tone === 'deletion'} class:insertion={tone === 'insertion'} class:slop={tone === 'slop'}></span>
134→                <span>{labelFor(change)}</span>
135→              </div>
136→              <div class="change-meta">
137→                <span class="change-index">{index + 1}</span>
138→                {#if annotated}
139→                  <span class="annotation-indicator">Note</span>
140→                {/if}
141→              </div>
142→            </div>
143→            <p class="change-preview">{summarize(change.text)}</p>
144→          </button>
145→        </li>
146→      {/each}
147→    </ol>
148→  {/if}
