241→/**
242→ * Split text into editorially meaningful diff tokens so rewrites stay coherent.
243→ * Whitespace remains explicit to preserve offsets and spacing edits.
244→ * @param {string} text
245→ * @returns {string[]}
246→ */
247→function tokenizeForDiff(text) {
248→  return text.match(TOKEN_PATTERN) || [];
249→}
250→
251→/**
252→ * Encode tokens into a compact character alphabet for diff-match-patch.
253→ * Mirrors DMP's line-mode compression, but at token granularity.
254→ * @param {string} text
255→ * @param {Map<string, number>} tokenMap
256→ * @param {string[]} tokenArray
257→ * @returns {string | null}
258→ */
259→function encodeTokenText(text, tokenMap, tokenArray) {
260→  const tokens = tokenizeForDiff(text);
261→  let encoded = '';
262→
263→  for (const token of tokens) {
264→    let code = tokenMap.get(token);
265→    if (typeof code !== 'number') {
266→      if (tokenArray.length >= MAX_TOKEN_ALPHABET) {
267→        return null;
268→      }
269→      code = tokenArray.length;
270→      tokenMap.set(token, code);
271→      tokenArray.push(token);
272→    }
273→    encoded += String.fromCharCode(code);
274→  }
275→
276→  return encoded;
277→}
278→
279→/**
280→ * Expand compressed token chars back into original token strings.
281→ * @param {string} compressed
282→ * @param {string[]} tokenArray
283→ * @returns {string}
284→ */
285→function decodeTokenText(compressed, tokenArray) {
286→  let text = '';
287→  for (const tokenChar of compressed) {
288→    text += tokenArray[tokenChar.charCodeAt(0)] || '';
289→  }
290→  return text;
291→}
292→
293→/**
294→ * Apply semantic cleanup to a diff op list.
295→ * @param {Array<[number, string]>} diffs
296→ */
297→function cleanupDiffs(diffs) {
298→  dmp.diff_cleanupSemantic(diffs);
299→  dmp.diff_cleanupSemanticLossless(diffs);
300→}
301→
302→/**
303→ * Compute a UI-facing diff with token compression when possible, falling back
304→ * to raw character diffing if the token alphabet would overflow.
305→ * @param {string} original
306→ * @param {string} edited
307→ * @returns {Array<[number, string]>}
308→ */
309→function computeTextDiffs(original, edited) {
310→  const tokenArray = [''];
311→  const tokenMap = new Map();
312→  const encodedOriginal = encodeTokenText(original, tokenMap, tokenArray);
313→  const encodedEdited = encodeTokenText(edited, tokenMap, tokenArray);
314→
315→  if (encodedOriginal !== null && encodedEdited !== null) {
316→    /** @type {Array<[number, string]>} */
317→    const tokenDiffs = /** @type {Array<[number, string]>} */ (
318→      dmp.diff_main(encodedOriginal, encodedEdited, false)
319→    );
320→    cleanupDiffs(tokenDiffs);
321→    return tokenDiffs.map(([operation, compressed]) => [
322→      operation,
323→      decodeTokenText(compressed, tokenArray),
324→    ]);
325→  }
326→
327→  /** @type {Array<[number, string]>} */
328→  const rawDiffs = /** @type {Array<[number, string]>} */ (dmp.diff_main(original, edited));
329→  cleanupDiffs(rawDiffs);
330→  return rawDiffs;
331→}
332→
333→/**
334→ * Compute the diff between original and edited text
335→ * @param {string} original - The original text
336→ * @param {string} edited - The edited text
337→ * @param {Change[]} [previousChanges] - Previous change snapshot for ID reconciliation
338→ * @param {string} [previousEditedText] - Previous edited text snapshot for context-aware matching
339→ * @returns {DiffResult}
340→ */
341→export function computeDiff(original, edited, previousChanges = [], previousEditedText = '') {
342→  /** @type {Array<[number, string]>} */
343→  const diffs = computeTextDiffs(original, edited);
344→
345→  /** @type {Change[]} */
346→  const changes = [];
347→  let deletions = 0;
348→  let insertions = 0;
349→
350→  // Track position in EDITED document (where decorations will appear)
351→  let editedOffset = 0;
352→
353→  for (const [operation, text] of diffs) {
354→    if (operation === -1) {
355→      // Deletion - text was removed, show at current edited position
356→      changes.push({
357→        id: generateChangeId('deletion', text, editedOffset),
358→        type: 'deletion',
359→        text,
360→        // editedOffset is where this deletion "happened" in the edited doc
361→        editedOffset,
362→        location: offsetToLocation(edited, editedOffset),
363→      });
364→      deletions++;
365→      // Don't advance editedOffset - deleted text isn't in edited doc
366→    } else if (operation === 1) {
367→      // Insertion - new text exists in edited doc
368→      changes.push({
369→        id: generateChangeId('insertion', text, editedOffset),
370→        type: 'insertion',
371→        text,
372→        editedOffset,
373→        location: offsetToLocation(edited, editedOffset),
374→      });
375→      insertions++;
376→      // Advance editedOffset by insertion length
377→      editedOffset += text.length;
378→    } else {
379→      // Equal - text exists in both, advance editedOffset
380→      editedOffset += text.length;
381→    }
382→  }
383→
384→  return {
385→    changes: reconcileChangeIds(
386→      changes.filter(c => c.type !== 'equal'),
387→      previousChanges,
388→      edited,
389→      previousEditedText
390→    ),
391→    deletions,
392→    insertions,
393→    // Attach text snapshots for decoration verification
394→    _originalText: original,
395→    _editedText: edited,
396→  };
397→}
398→
399→/**
400→ * Find contiguous change groups (deletion followed by insertion at same position)
401→ * These represent replacements
402→ * @param {Change[]} changes
403→ * @returns {Change[][]}
404→ */
405→export function groupChanges(changes) {
406→  /** @type {Change[][]} */
407→  const groups = [];
408→  /** @type {Change[]} */
409→  let currentGroup = [];
410→
411→  for (let i = 0; i < changes.length; i++) {
412→    const change = changes[i];
413→    const prevChange = changes[i - 1];
414→
415→    if (currentGroup.length === 0) {
416→      currentGroup.push(change);
417→    } else {
418→      // Check if this change is adjacent to the previous one
419→      const lastInGroup = currentGroup[currentGroup.length - 1];
420→      const sameLocation =
421→        lastInGroup.location.line === change.location.line &&
422→        lastInGroup.location.col === change.location.col;
423→      const isReplacementPair =
424→        lastInGroup.type === 'deletion' && change.type === 'insertion' && sameLocation;
425→
426→      if (isReplacementPair) {
427→        currentGroup.push(change);
428→      } else {
429→        groups.push(currentGroup);
430→        currentGroup = [change];
431→      }
432→    }
433→  }
434→
435→  if (currentGroup.length > 0) {
436→    groups.push(currentGroup);
437→  }
438→
439→  return groups;
440→}
441→
442→/**
443→ * Get lines that have changes
444→ * @param {Change[]} changes
445→ * @returns {Set<number>}
446→ */
447→export function getLinesWithChanges(changes) {
448→  const lines = new Set();
449→  for (const change of changes) {
450→    lines.add(change.location.line);
451→    // For multi-line changes, add all lines
452→    const newlines = (change.text.match(/\n/g) || []).length;
453→    for (let i = 1; i <= newlines; i++) {
454→      lines.add(change.location.line + i);
455→    }
456→  }
457→  return lines;
458→}
459→
460→/**
461→ * Create a summary of changes for display
462→ * @param {DiffResult} diffResult
463→ * @returns {string}
464→ */
465→export function summarizeChanges(diffResult) {
466→  const parts = [];
467→  if (diffResult.deletions > 0) {
468→    parts.push(`${diffResult.deletions} deletion${diffResult.deletions > 1 ? 's' : ''}`);
469→  }
470→  if (diffResult.insertions > 0) {
471→    parts.push(`${diffResult.insertions} insertion${diffResult.insertions > 1 ? 's' : ''}`);
472→  }
473→  return parts.join(', ') || 'No changes';
474→}
