175→/** Lines that violate tone or WRITING.md bans */
176→export const linesWithSlop = derived(
177→  [editedPlainText, slopMatchers],
178→  ([$text, $matchers]) => {
179→    if (!$text || !$matchers || $matchers.length === 0) return new Set();
180→    const lines = $text.split(/\r?\n/);
181→    const result = new Set();
182→    const compiled = $matchers.map((matcher) => ({
183→      label: matcher.label,
184→      regex: new RegExp(matcher.pattern, matcher.flags),
185→    }));
186→    lines.forEach((line, index) => {
187→      for (const matcher of compiled) {
188→        if (!matcher?.regex) continue;
189→        matcher.regex.lastIndex = 0;
190→        if (matcher.regex.test(line)) {
191→          result.add(index + 1);
192→          break;
193→        }
194→      }
195→    });
196→    return result;
197→  }
