 66→    if (!editor || !isReady) return null;
 67→    try {
 68→      return editor.ctx.get(editorViewCtx);
 69→    } catch (error) {
 70→      reportRuntimeError('editor_view_unavailable', error);
 71→      return null;
 72→    }
 73→  }
 74→
 75→  function getCurrentPlainText() {
 76→    const view = getEditorView();
 77→    if (!view) return '';
 78→    try {
 79→      return buildTextMap(view.state.doc).text;
 80→    } catch (error) {
 81→      reportRuntimeError('editor_plain_text_extract_failed', error);
 82→      return '';
 83→    }
 84→  }
 85→
 86→  function queueAnchorRefresh() {
 87→    if (typeof window === 'undefined') return;
 88→    if (anchorRefreshHandle) {
 89→      window.cancelAnimationFrame(anchorRefreshHandle);
 90→    }
 91→    anchorRefreshHandle = window.requestAnimationFrame(() => {
 92→      anchorRefreshHandle = 0;
 93→      refreshAnchors();
 94→    });
 95→  }
 96→
 97→  /**
 98→   * @param {number} pos
 99→   * @param {import('@milkdown/prose/view').EditorView} view
100→   */
101→  function resolveBlockElement(pos, view) {
102→    const boundedPos = Math.max(1, Math.min(pos, view.state.doc.content.size));
103→    const resolved = view.domAtPos(boundedPos);
104→    const element =
105→      resolved.node instanceof Text
106→        ? resolved.node.parentElement
107→        : resolved.node instanceof HTMLElement
108→          ? resolved.node
109→          : null;
110→
111→    if (!(element instanceof HTMLElement)) {
112→      return null;
113→    }
114→
115→    return element.closest('p, h1, h2, h3, h4, h5, h6, li, blockquote, pre, hr');
116→  }
117→
118→  /**
119→   * @param {string} text
120→   * @param {number} [limit]
121→   */
122→  function summarize(text, limit = 28) {
123→    const normalized = text.replace(/\s+/g, ' ').trim();
124→    if (!normalized) return '';
125→    if (normalized.length <= limit) return normalized;
126→    return `${normalized.slice(0, limit)}…`;
127→  }
128→
129→  function refreshAnchors() {
130→    const view = getEditorView();
131→    if (!view || !editorShell || !editorFrame || !diffResult?.changes?.length) {
132→      anchorMarks = [];
133→      return;
134→    }
135→
136→    try {
137→      const textMap = buildTextMap(view.state.doc);
138→      if (diffResult?._editedText && textMap.text !== diffResult._editedText) {
139→        anchorMarks = [];
140→        return;
141→      }
142→
143→      /** @type {Map<string, AnchorMark & { sortOffset: number }>} */
144→      const groups = new Map();
145→      const frameRect = editorFrame.getBoundingClientRect();
146→      const offsets = textMap.offsets;
147→      const sortedChanges = [...diffResult.changes].sort((left, right) => left.editedOffset - right.editedOffset);
148→
149→      for (const [index, change] of sortedChanges.entries()) {
150→        const offsetIndex = Math.max(0, Math.min(change.editedOffset, offsets.length - 1));
151→        const docPos = offsets[offsetIndex];
152→        if (typeof docPos !== 'number') continue;
153→
154→        const blockEl = resolveBlockElement(docPos, view);
155→        if (!(blockEl instanceof HTMLElement)) continue;
156→
157→        const rect = blockEl.getBoundingClientRect();
158→        const top = rect.top - frameRect.top + editorShell.scrollTop;
159→        const height = Math.max(20, Math.min(rect.height, 96));
160→        const key = `${Math.round(top)}:${Math.round(height)}`;
161→        const existing = groups.get(key);
162→        const annotated = annotations.has(change.id);
163→        const flagged = slopLines.has(change.location.line);
164→        const markType = flagged ? 'slop' : change.type;
165→
166→        if (existing) {
167→          existing.changeIds.push(change.id);
168→          existing.annotated = existing.annotated || annotated;
169→          existing.selected = existing.selected || selectedChangeId === change.id;
170→          if (existing.type !== 'slop' && markType === 'slop') {
171→            existing.type = 'slop';
172→          }
173→          if (selectedChangeId === change.id) {
174→            existing.id = change.id;
175→            existing.preview = summarize(change.text);
176→          }
177→          continue;
178→        }
179→
180→        groups.set(key, {
181→          id: change.id,
182→          top,
183→          height,
184→          index: index + 1,
185→          type: markType,
186→          selected: selectedChangeId === change.id,
187→          annotated,
188→          preview: summarize(change.text),
189→          changeIds: [change.id],
190→          sortOffset: change.editedOffset,
191→        });
192→      }
193→
194→      anchorMarks = [...groups.values()]
195→        .sort((left, right) => left.sortOffset - right.sortOffset)
196→        .map(({ sortOffset, ...mark }) => mark);
197→    } catch (error) {
198→      reportRuntimeError('editor_anchor_refresh_failed', error);
199→      anchorMarks = [];
200→    }
201→  }
202→
203→  function setupObservers() {
204→    if (typeof ResizeObserver === 'undefined') return;
205→    resizeObserver = new ResizeObserver(() => {
206→      queueAnchorRefresh();
207→    });
208→    if (editorFrame) resizeObserver.observe(editorFrame);
209→    if (editorShell) resizeObserver.observe(editorShell);
210→  }
211→
212→  /**
213→   * @param {string} initialContent
214→   */
215→  async function initEditor(initialContent) {
216→    if (!editorRoot) return;
217→
218→    try {
219→      editor = await Editor.make()
220→        .config((ctx) => {
221→          ctx.set(rootCtx, editorRoot);
222→          ctx.set(defaultValueCtx, initialContent || '');
223→
224→          const listenerManager = ctx.get(listenerCtx);
225→          listenerManager.markdownUpdated((ctx, markdown) => {
226→            if (!isInternalUpdate && markdown !== lastKnownContent) {
227→              lastKnownContent = markdown;
228→              onChange(markdown);
229→
230→              const plainText = getCurrentPlainText();
231→              onPlainTextChange(plainText);
232→
233→              if (diffUpdateTimeout) {
234→                clearTimeout(diffUpdateTimeout);
235→              }
236→              diffUpdateTimeout = setTimeout(() => {
237→                if (editor) {
238→                  try {
239→                    triggerDiffUpdate(editor);
240→                    queueAnchorRefresh();
241→                  } catch (error) {
242→                    reportRuntimeError('editor_diff_refresh_failed', error);
243→                  }
244→                }
245→              }, DIFF_DEBOUNCE_MS);
246→            }
247→          });
248→        })
249→        .use(commonmark)
250→        .use(historyPlugin)
251→        .use(historyKeymapPlugin)
252→        .use(listener)
253→        .use(createDiffPlugin(getDiffResult, onClickChange, () => selectedChangeId))
254→        .use(createSlopPlugin(getSlopMatchers))
255→        .create();
256→
257→      isReady = true;
258→      lastKnownContent = initialContent;
259→      setupObservers();
260→
261→      setTimeout(() => {
262→        if (!hasCalledInitialRender) {
263→          const plainText = getCurrentPlainText();
264→          if (plainText) {
265→            hasCalledInitialRender = true;
266→            onInitialRender(plainText);
267→          }
268→          queueAnchorRefresh();
269→        }
270→      }, 50);
271→
272→      editorRoot.addEventListener('click', updateLineNumber);
273→      editorRoot.addEventListener('keyup', updateLineNumber);
274→    } catch (error) {
275→      reportRuntimeError('editor_init_failed', error);
276→    }
277→  }
278→
279→  function updateLineNumber() {
280→    const view = getEditorView();
281→    if (!view) return;
282→    try {
283→      const pos = view.state.selection.anchor;
284→      const doc = view.state.doc;
285→      let line = 1;
286→      doc.descendants((node, nodePos) => {
287→        if (nodePos >= pos) return false;
288→        if (node.isTextblock) line++;
289→        return true;
290→      });
291→      onLineChange(Math.max(1, line));
292→    } catch (error) {
293→      reportRuntimeError('editor_line_tracking_failed', error);
294→    }
295→  }
296→
297→  /** @param {Event & { currentTarget: HTMLElement }} event */
298→  function handleScroll(event) {
299→    onScroll(event.currentTarget.scrollTop);
300→  }
301→
302→  function getLineHeightPx() {
303→    if (typeof window === 'undefined') return 0;
304→    const rootStyle = getComputedStyle(document.documentElement);
305→    const raw = rootStyle.getPropertyValue('--line-height').trim();
306→    const rootFontSize = parseFloat(rootStyle.fontSize) || 16;
307→    if (raw.endsWith('rem')) {
308→      return parseFloat(raw) * rootFontSize;
309→    }
310→    if (raw.endsWith('px')) {
311→      return parseFloat(raw);
312→    }
313→    const parsed = parseFloat(raw);
314→    return Number.isNaN(parsed) ? 0 : parsed;
315→  }
316→
317→  onMount(() => {
318→    if (content) {
319→      initEditor(content);
320→    }
321→  });
322→
323→  onDestroy(() => {
324→    if (diffUpdateTimeout) {
325→      clearTimeout(diffUpdateTimeout);
326→    }
327→    if (anchorRefreshHandle && typeof window !== 'undefined') {
328→      window.cancelAnimationFrame(anchorRefreshHandle);
329→    }
330→    resizeObserver?.disconnect();
331→    if (editorRoot) {
332→      editorRoot.removeEventListener('click', updateLineNumber);
333→      editorRoot.removeEventListener('keyup', updateLineNumber);
334→    }
335→    editor?.destroy();
336→  });
337→
338→  $effect(() => {
339→    const currentContent = content;
340→
341→    if (!currentContent) return;
342→
343→    if (!isReady && currentContent && editorRoot) {
344→      initEditor(currentContent);
345→      return;
346→    }
347→
348→    if (isReady && editor && currentContent !== lastKnownContent) {
349→      try {
350→        isInternalUpdate = true;
351→        editor.action(milkdownUtils.replaceAll(currentContent));
352→        lastKnownContent = currentContent;
353→        setTimeout(() => {
354→          isInternalUpdate = false;
355→          if (editor) {
356→            triggerDiffUpdate(editor);
357→            queueAnchorRefresh();
358→          }
359→        }, 0);
360→      } catch (error) {
361→        reportRuntimeError('editor_external_sync_failed', error);
362→        isInternalUpdate = false;
363→      }
364→    }
365→  });
366→
367→  $effect(() => {
368→    diffResult;
369→    selectedChangeId;
370→    annotations;
371→    slopLines;
372→    densityMode;
373→    if (isReady) {
374→      try {
375→        if (editor) {
376→          triggerDiffUpdate(editor);
377→        }
378→      } catch (error) {
379→        reportRuntimeError('editor_diff_refresh_failed', error);
380→      }
381→      queueAnchorRefresh();
382→    }
383→  });
384→
385→  export function getContent() {
386→    if (!editor || !isReady) return '';
387→    try {
388→      return editor.action(milkdownUtils.getMarkdown());
389→    } catch (error) {
390→      reportRuntimeError('editor_markdown_read_failed', error);
391→      return '';
392→    }
393→  }
394→
395→  export function focus() {
396→    const view = getEditorView();
397→    view?.focus();
398→  }
399→
400→  export function refreshDiff() {
401→    if (!editor || !isReady) return;
402→    try {
403→      triggerDiffUpdate(editor);
404→      queueAnchorRefresh();
405→    } catch (error) {
406→      reportRuntimeError('editor_diff_refresh_failed', error);
407→    }
408→  }
409→
410→  export function refreshSlop() {
411→    if (!editor || !isReady) return;
412→    try {
413→      triggerSlopUpdate(editor);
414→      queueAnchorRefresh();
415→    } catch (error) {
416→      reportRuntimeError('editor_slop_refresh_failed', error);
417→    }
418→  }
419→
420→  /** @param {number} scrollTop */
421→  export function setScrollTop(scrollTop) {
422→    if (!editorShell) return;
423→    if (Math.abs(editorShell.scrollTop - scrollTop) < 1) return;
424→    editorShell.scrollTop = scrollTop;
425→  }
426→
427→  /** @param {number} lineNumber */
428→  export function scrollToLine(lineNumber) {
429→    if (!editorShell) return;
430→    const lineHeight = getLineHeightPx() || 28;
431→    const targetTop = Math.max(0, Math.round((lineNumber - 1) * lineHeight));
432→    editorShell.scrollTo({ top: targetTop, behavior: 'auto' });
433→  }
434→
435→  /** @param {string} changeId */
436→  export function scrollToChange(changeId) {
437→    if (!editorShell || !changeId) return;
438→    const mark = anchorMarks.find((item) => item.changeIds.includes(changeId) || item.id === changeId);
439→    if (mark) {
440→      editorShell.scrollTo({
441→        top: Math.max(0, Math.round(mark.top - 96)),
442→        behavior: 'auto',
443→      });
444→      return;
445→    }
446→    const change = diffResult?.changes?.find(
447→      /** @param {import('../utils/diff.js').Change} item */
448→      (item) => item.id === changeId
449→    );
450→    if (change) {
451→      scrollToLine(change.location.line);
452→    }
453→  }
454→
455→  /**
456→   * @param {AnchorMark} mark
457→   * @param {MouseEvent} event
458→   */
459→  function handleAnchorClick(mark, event) {
460→    const target = event.currentTarget;
461→    if (!(target instanceof HTMLElement)) return;
462→    const rect = target.getBoundingClientRect();
463→    onSelectAnchor(mark.id, rect.right + 8, rect.top);
464→  }
465→</script>
