 46→/**
 47→ * @param {string} title
 48→ */
 49→function buildTitleKeywords(title) {
 50→  const raw = title.trim();
 51→  const keywords = new Set();
 52→  if (!raw) return [];
 53→
 54→  const lower = raw.toLowerCase();
 55→  keywords.add(normalize(lower));
 56→  keywords.add(normalize(lower.replace(/-/g, ' ')));
 57→  keywords.add(normalize(lower.replace(/-/g, '')));
 58→
 59→  const tokens = tokenize(lower).filter((token) => token.length > 2 && !STOP_WORDS.has(token));
 60→  tokens.forEach((token) => keywords.add(token));
 61→  if (tokens.length > 1) {
 62→    keywords.add(tokens.join(' '));
 63→  }
 64→
 65→  return Array.from(keywords).filter(Boolean);
 66→}
