 97→    if (trimmed.startsWith('### ')) {
 98→      const heading = trimmed.slice(4).trim();
 99→      currentBannedSection = heading.startsWith('Banned ') ? heading : null;
100→      continue;
101→    }
102→
103→    const numberedRule = trimmed.match(/^\d+\.\s+\*\*(.+?)\*\*/);
104→    if (numberedRule) {
105→      const title = numberedRule[1].trim();
106→      rules.push({
107→        label: title,
108→        keywords: buildTitleKeywords(title),
109→        section: currentSection,
110→      });
111→      continue;
112→    }
113→
114→    if (currentBannedSection) {
115→      const items = parseBannedList(trimmed);
116→      for (const item of items) {
117→        const keyword = normalize(item);
118→        if (!keyword) continue;
119→        rules.push({
120→          label: `${currentBannedSection}: ${item}`,
121→          keywords: [keyword],
122→          section: currentBannedSection,
123→        });
124→      }
125→    }
126→  }
127→
128→  return rules;
129→}
130→
131→/**
132→ * @param {string} text
133→ */
134→export function createWritingRuleMatcher(text) {
135→  const rules = parseWritingRules(text);
136→  /** @type {Array<{ keyword: string, label: string, isPhrase: boolean }>} */
137→  const index = [];
138→
139→  for (const rule of rules) {
140→    for (const keyword of rule.keywords) {
141→      const normalized = normalize(keyword);
142→      if (normalized.length < 3) continue;
143→      index.push({
144→        keyword: normalized,
145→        label: rule.label,
146→        isPhrase: normalized.includes(' '),
147→      });
148→    }
149→  }
150→
151→  index.sort((a, b) => b.keyword.length - a.keyword.length);
152→
153→  return {
154→    rules,
155→    /**
156→     * @param {string} rationale
157→     */
158→    match(rationale) {
159→      const normalized = normalize(rationale);
160→      if (!normalized) return null;
161→      const tokens = new Set(normalized.split(' ').filter(Boolean));
162→      for (const entry of index) {
163→        if (entry.isPhrase) {
164→          if (normalized.includes(entry.keyword)) return entry.label;
165→        } else if (tokens.has(entry.keyword)) {
166→          return entry.label;
167→        }
168→      }
169→      return null;
170→    },
171→  };
172→}
173→
174→/**
175→ * @param {string} text
176→ */
177→function escapeRegExp(text) {
178→  return text.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
179→}
180→
181→/**
182→ * @param {string} text
183→ */
184→function toRuleKey(text) {
185→  return normalize(text).replace(/\s+/g, '_').replace(/[^a-z0-9_]/g, '');
186→}
187→
188→/**
189→ * @param {string} text
190→ */
191→export function createViolationMatchers(text) {
192→  const rules = parseWritingRules(text);
193→  const matchers = [];
194→
195→  for (const rule of rules) {
196→    if (rule.section && rule.section.startsWith('Banned ')) {
197→      const parts = rule.label.split(':');
198→      const word = parts.length > 1 ? parts.slice(1).join(':').trim() : rule.label;
199→      if (!word) continue;
200→      matchers.push({
201→        id: `writing.${toRuleKey(word)}`,
202→        label: rule.label,
203→        pattern: `\\b${escapeRegExp(word)}\\b`,
204→        flags: 'g',
205→        category: 'writing',
206→      });
207→    }
208→  }
209→
210→  const hasEmDashRule = rules.some((rule) => rule.label.toLowerCase().includes('em-dash'));
211→  if (hasEmDashRule) {
212→    matchers.push({
213→      id: 'writing.no_em_dash',
214→      label: 'No Em-Dashes',
215→      pattern: '—|--',
216→      flags: 'g',
217→      category: 'writing',
218→    });
219→  }
220→
221→  return matchers;
222→}
