  7→/**
  8→ * @typedef {Object} Change
  9→ * @property {string} id - Unique identifier for the change
 10→ * @property {'deletion' | 'insertion' | 'equal'} type - Type of change
 11→ * @property {string} text - The text content
 12→ * @property {number} editedOffset - Character position in the edited document
 13→ * @property {{ line: number, col: number }} location - Position in the document (legacy)
 14→ */
 15→
 16→/**
 17→ * @typedef {Object} DiffResult
 18→ * @property {Change[]} changes - List of all changes
 19→ * @property {number} deletions - Number of deletions
 20→ * @property {number} insertions - Number of insertions
 21→ * @property {string} [_originalText] - Original text snapshot for verification
 22→ * @property {string} [_editedText] - Edited text snapshot for verification
 23→ */
 24→
 25→/**
 26→ * Generate a deterministic ID seed for a change based on content and position.
 27→ * This is used for newly discovered changes. Existing IDs are preserved by
 28→ * reconcileChangeIds when we can match against the previous diff snapshot.
 29→ * @param {string} type - 'deletion' or 'insertion'
 30→ * @param {string} text - The changed text
 31→ * @param {number} offset - Position in edited document
 32→ * @returns {string}
 33→ */
 34→function generateChangeId(type, text, offset) {
 35→  const input = `${type}|${offset}|${text.length}|${text}`;
 36→  let hash = 0;
 37→  for (let i = 0; i < input.length; i++) {
 38→    hash = ((hash << 5) - hash + input.charCodeAt(i)) | 0;
 39→  }
 40→  return 'c_' + Math.abs(hash).toString(36);
 41→}
 42→
 43→/**
 44→ * Normalize text for fuzzy matching.
 45→ * @param {string} text
 46→ * @returns {string}
 47→ */
 48→function normalizeText(text) {
 49→  return text.replace(/\s+/g, ' ').trim().toLowerCase();
 50→}
 51→
 52→/**
 53→ * Build a multiset of character bigrams.
 54→ * @param {string} text
 55→ * @returns {Map<string, number>}
 56→ */
 57→function buildBigrams(text) {
 58→  /** @type {Map<string, number>} */
 59→  const grams = new Map();
 60→  if (!text) return grams;
 61→  if (text.length === 1) {
 62→    grams.set(text, 1);
 63→    return grams;
 64→  }
 65→  for (let i = 0; i < text.length - 1; i++) {
 66→    const gram = text.slice(i, i + 2);
 67→    grams.set(gram, (grams.get(gram) || 0) + 1);
 68→  }
 69→  return grams;
 70→}
 71→
 72→/**
 73→ * Compute a Sørensen-Dice-like similarity score for changed text.
 74→ * @param {string} a
 75→ * @param {string} b
 76→ * @returns {number}
 77→ */
 78→function textSimilarity(a, b) {
 79→  const left = normalizeText(a);
 80→  const right = normalizeText(b);
 81→  if (!left || !right) return 0;
 82→  if (left === right) return 1;
 83→  if (left.includes(right) || right.includes(left)) {
 84→    return Math.min(left.length, right.length) / Math.max(left.length, right.length);
 85→  }
 86→
 87→  const leftBigrams = buildBigrams(left);
 88→  const rightBigrams = buildBigrams(right);
 89→  if (leftBigrams.size === 0 || rightBigrams.size === 0) return 0;
 90→
 91→  let intersection = 0;
 92→  let leftCount = 0;
 93→  let rightCount = 0;
 94→
 95→  for (const count of leftBigrams.values()) leftCount += count;
 96→  for (const count of rightBigrams.values()) rightCount += count;
 97→
 98→  for (const [gram, leftGramCount] of leftBigrams) {
 99→    const rightGramCount = rightBigrams.get(gram) || 0;
100→    intersection += Math.min(leftGramCount, rightGramCount);
101→  }
102→
103→  return (2 * intersection) / (leftCount + rightCount);
104→}
105→
106→/**
107→ * Build a local context anchor around a change offset.
108→ * Anchors help us keep IDs stable when multiple changes have similar text.
109→ * @param {string} text
110→ * @param {number} offset
111→ * @param {number} [radius]
112→ * @returns {{ before: string, after: string }}
113→ */
114→function buildContextAnchor(text, offset, radius = 32) {
115→  if (!text || offset < 0) {
116→    return { before: '', after: '' };
117→  }
118→  const start = Math.max(0, offset - radius);
119→  const end = Math.min(text.length, offset + radius);
120→  return {
121→    before: normalizeText(text.slice(start, offset)),
122→    after: normalizeText(text.slice(offset, end)),
123→  };
124→}
125→
126→/**
127→ * Score how similar two context anchors are.
128→ * @param {{ before: string, after: string }} left
129→ * @param {{ before: string, after: string }} right
130→ * @returns {number}
131→ */
132→function anchorSimilarity(left, right) {
133→  const before = left.before && right.before ? textSimilarity(left.before, right.before) : 0;
134→  const after = left.after && right.after ? textSimilarity(left.after, right.after) : 0;
135→  const signals = (left.before && right.before ? 1 : 0) + (left.after && right.after ? 1 : 0);
136→  if (signals === 0) return 0;
137→  return (before + after) / signals;
138→}
