140→/**
141→ * Reconcile change IDs with a previous change set so annotations survive
142→ * routine offset shifts while the user keeps editing.
143→ * @param {Change[]} nextChanges
144→ * @param {Change[]} previousChanges
145→ * @param {string} editedText
146→ * @param {string} previousEditedText
147→ * @returns {Change[]}
148→ */
149→function reconcileChangeIds(nextChanges, previousChanges, editedText, previousEditedText) {
150→  if (!Array.isArray(previousChanges) || previousChanges.length === 0) {
151→    return nextChanges;
152→  }
153→
154→  /** @type {Map<string, Change[]>} */
155→  const previousByType = new Map();
156→  for (const prev of previousChanges) {
157→    const bucket = previousByType.get(prev.type) || [];
158→    bucket.push(prev);
159→    previousByType.set(prev.type, bucket);
160→  }
161→
162→  const usedPreviousIds = new Set();
163→  const MIN_SIMILARITY = 0.34;
164→  const DISTANCE_WEIGHT = 0.00015;
165→  const TEXT_WEIGHT = 0.74;
166→  const ANCHOR_WEIGHT = 0.26;
167→  const hasPreviousContext = typeof previousEditedText === 'string' && previousEditedText.length > 0;
168→
169→  /** @type {Map<string, { before: string, after: string }>} */
170→  const previousAnchorsById = new Map();
171→  if (hasPreviousContext) {
172→    for (const previous of previousChanges) {
173→      previousAnchorsById.set(
174→        previous.id,
175→        buildContextAnchor(previousEditedText, previous.editedOffset)
176→      );
177→    }
178→  }
179→
180→  return nextChanges.map((change) => {
181→    const candidates = previousByType.get(change.type);
182→    if (!candidates || candidates.length === 0) {
183→      return change;
184→    }
185→
186→    const changeAnchor = buildContextAnchor(editedText, change.editedOffset);
187→    let bestCandidate = null;
188→    let bestScore = Number.NEGATIVE_INFINITY;
189→    let bestSimilarity = 0;
190→
191→    for (const candidate of candidates) {
192→      if (usedPreviousIds.has(candidate.id)) continue;
193→      const textScore = textSimilarity(change.text, candidate.text);
194→      if (textScore <= 0) continue;
195→      if (textScore < MIN_SIMILARITY) continue;
196→
197→      const candidateAnchor = previousAnchorsById.get(candidate.id) || { before: '', after: '' };
198→      const contextScore = hasPreviousContext ? anchorSimilarity(changeAnchor, candidateAnchor) : 0;
199→      const distance = Math.abs(candidate.editedOffset - change.editedOffset);
200→      const score =
201→        textScore * TEXT_WEIGHT + contextScore * ANCHOR_WEIGHT - distance * DISTANCE_WEIGHT;
202→      if (score > bestScore) {
203→        bestScore = score;
204→        bestSimilarity = textScore;
205→        bestCandidate = candidate;
206→      }
207→    }
208→
209→    if (!bestCandidate || bestSimilarity < MIN_SIMILARITY) {
210→      return change;
211→    }
212→
213→    usedPreviousIds.add(bestCandidate.id);
214→    return {
215→      ...change,
216→      id: bestCandidate.id,
217→    };
218→  });
219→}
