221→/**
222→ * Convert a character offset to line/col in text
223→ * @param {string} text - The text to compute position in
224→ * @param {number} offset - Character offset
225→ * @returns {{ line: number, col: number }}
226→ */
227→function offsetToLocation(text, offset) {
228→  let line = 1;
229→  let col = 0;
230→  for (let i = 0; i < offset && i < text.length; i++) {
231→    if (text[i] === '\n') {
232→      line++;
233→      col = 0;
234→    } else {
235→      col++;
236→    }
237→  }
238→  return { line, col };
239→}
