 44→function createDiffDecorations(doc, textMap, diffResult, selectedChangeId, onClickChange) {
 45→  if (!diffResult || !diffResult.changes || diffResult.changes.length === 0) {
 46→    return DecorationSet.empty;
 47→  }
 48→
 49→  const offsets = textMap.offsets;
 50→  const hasSnapshot = typeof diffResult._editedText === 'string';
 51→  const isFresh = !hasSnapshot || textMap.text === diffResult._editedText;
 52→
 53→  if (!isFresh) {
 54→    return DecorationSet.empty;
 55→  }
 56→
 57→  /** @param {number} offset */
 58→  const offsetToPos = (offset) => {
 59→    // Return null for any invalid offset - widget will be skipped
 60→    if (!offsets || offsets.length === 0) return null;
 61→    if (offset < 0) return null;
 62→    // offsets now has a sentinel at the end, so length is text.length + 1
 63→    if (offset >= offsets.length) return null;
 64→    return offsets[offset];
 65→  };
 66→
 67→  const decorations = [];
 68→
 69→  for (const change of diffResult.changes) {
 70→    // Skip whitespace-only changes to reduce noise
 71→    if (!change.text || change.text.trim().length === 0) {
 72→      continue;
 73→    }
 74→
 75→    const docPos = offsetToPos(change.editedOffset);
 76→    if (docPos === null) {
 77→      continue;
 78→    }
 79→
 80→    if (change.type === 'deletion') {
 81→      decorations.push(
 82→        Decoration.widget(docPos, () => createDeletionWidget(change, selectedChangeId === change.id), {
 83→          side: -1,
 84→          key: change.id,
 85→          ignoreSelection: true,
 86→        })
 87→      );
 88→    } else if (change.type === 'insertion') {
 89→      // Inline decoration - highlights the inserted text
 90→      // Use an exclusive end offset so we highlight the full insertion.
 91→      // offsets[endOffset] maps to the position *after* the last inserted char.
 92→      const endOffset = change.editedOffset + change.text.length;
 93→      let endPos = offsetToPos(endOffset);
 94→
 95→      if (endOffset > 0) {
 96→        const lastCharPos = offsetToPos(endOffset - 1);
 97→        if (lastCharPos !== null) {
 98→          const minEndPos = lastCharPos + 1;
 99→          if (endPos === null || endPos < minEndPos) {
100→            endPos = minEndPos;
101→          }
102→        }
103→      }
104→
105→      if (endPos !== null && endPos > docPos) {
106→        decorations.push(
107→          Decoration.inline(docPos, endPos, {
108→            class: selectedChangeId === change.id ? 'added selected' : 'added',
109→            'data-change-id': change.id,
110→            'data-change-text': change.text,
111→            'data-change-type': 'insertion',
112→          })
113→        );
114→      }
115→    }
116→  }
117→
118→  return DecorationSet.create(doc, decorations);
119→}
