121→/** @type {ChangeClickHandler | null} */
122→let currentClickHandler = null;
123→
124→/**
125→ * Create the diff decoration plugin
126→ */
127→/**
128→ * @param {() => DiffResult | null} getDiffResult
129→ * @param {ChangeClickHandler} onClickChange
130→ * @param {() => string | null} [getSelectedChangeId]
131→ */
132→export function createDiffPlugin(getDiffResult, onClickChange, getSelectedChangeId = () => null) {
133→  currentClickHandler = onClickChange;
134→
135→  return $prose((ctx) => {
136→    return new Plugin({
137→      key: diffPluginKey,
138→
139→      state: {
140→        init(_, state) {
141→          const diffResult = getDiffResult();
142→          const textMap = buildTextMap(state.doc);
143→          return createDiffDecorations(state.doc, textMap, diffResult, getSelectedChangeId(), currentClickHandler);
144→        },
145→
146→        apply(tr, oldDecorations, oldState, newState) {
147→          if (tr.docChanged || tr.getMeta(diffPluginKey) === 'update') {
148→            const diffResult = getDiffResult();
149→            if (!diffResult || !diffResult.changes) {
150→              return DecorationSet.empty;
151→            }
152→            if (diffResult.changes.length === 0) {
153→              return DecorationSet.empty;
154→            }
155→            const textMap = buildTextMap(newState.doc);
156→            return createDiffDecorations(newState.doc, textMap, diffResult, getSelectedChangeId(), currentClickHandler);
157→          }
158→          return oldDecorations.map(tr.mapping, tr.doc);
159→        },
160→      },
161→
162→      props: {
163→        decorations(state) {
164→          return this.getState(state);
165→        },
166→
167→        handleClick(view, pos, event) {
168→          const target = event.target;
169→          if (target instanceof HTMLElement && currentClickHandler) {
170→            const changeEl = target.closest('[data-change-id]');
171→            if (!(changeEl instanceof HTMLElement)) {
172→              return false;
173→            }
174→            const changeId = changeEl.dataset?.changeId;
175→            const changeText = changeEl.dataset?.changeText;
176→
177→            if (changeId && changeText) {
178→              const rect = changeEl.getBoundingClientRect();
179→              // Position popover to the right of the element
180→              currentClickHandler(changeId, changeText, rect.right + 8, rect.top);
181→              return true;
182→            }
183→          }
184→          return false;
185→        },
186→      },
187→    });
188→  });
189→}
