 73→/** Computed diff between original and edited PLAIN TEXT (what user sees) */
 74→export const diffResult = derived(
 75→  [originalPlainText, editedPlainText],
 76→  ([$originalText, $editedText]) => {
 77→    // Wait until both stores have content (avoid race condition during initialization)
 78→    if (!$originalText || !$editedText) {
 79→      previousDiffSnapshot = null;
 80→      previousOriginalForSnapshot = '';
 81→      return null;
 82→    }
 83→
 84→    if ($originalText !== previousOriginalForSnapshot) {
 85→      previousDiffSnapshot = null;
 86→      previousOriginalForSnapshot = $originalText;
 87→    }
 88→
 89→    if ($originalText === $editedText) {
 90→      const empty = {
 91→        changes: [],
 92→        deletions: 0,
 93→        insertions: 0,
 94→        _originalText: $originalText,
 95→        _editedText: $editedText,
 96→      };
 97→      previousDiffSnapshot = empty;
 98→      return empty;
 99→    }
100→    const next = computeDiff(
101→      $originalText,
102→      $editedText,
103→      previousDiffSnapshot?.changes || [],
104→      previousDiffSnapshot?._editedText || ''
105→    );
106→    previousDiffSnapshot = next;
107→    return next;
108→  }
109→);
