111→/** Whether the document has been modified */
112→export const hasChanges = derived(
113→  [originalContent, editedContent],
114→  ([$original, $edited]) => $original !== $edited
115→);
116→
117→/** Grouped changes for display */
118→export const changeGroups = derived(diffResult, ($diff) => {
119→  if (!$diff) return [];
120→  return groupChanges($diff.changes);
121→});
122→
123→/** Lines that have changes */
124→export const linesWithChanges = derived(diffResult, ($diff) => {
125→  if (!$diff) return new Set();
126→  return getLinesWithChanges($diff.changes);
127→});
128→
129→/** Summary text */
130→export const changeSummary = derived(diffResult, ($diff) => {
131→  if (!$diff) return 'No changes';
132→  return summarizeChanges($diff);
133→});
134→
135→/** Selected change object */
136→export const selectedChange = derived(
137→  [diffResult, selectedChangeId],
138→  ([$diff, $selectedChangeId]) => {
139→    if (!$diff || !$selectedChangeId) return null;
140→    return $diff.changes.find((change) => change.id === $selectedChangeId) || null;
141→  }
142→);
143→
144→/** Annotated changes in document order */
145→export const annotatedChanges = derived(
146→  [diffResult, annotations],
147→  ([$diff, $annotations]) => {
148→    if (!$diff || !$annotations || $annotations.size === 0) return [];
149→    return $diff.changes
150→      .map((change) => ({
151→        change,
152→        annotation: $annotations.get(change.id),
153→      }))
154→      .filter((entry) => entry.annotation)
155→      .sort((left, right) => left.change.editedOffset - right.change.editedOffset);
156→  }
157→);
158→
159→/** Lines that have annotations */
160→export const linesWithAnnotations = derived(
161→  [diffResult, annotations],
162→  ([$diff, $annotations]) => {
163→    if (!$diff) return new Set();
164→    const lines = new Set();
165→    for (const [changeId, annotation] of $annotations) {
166→      const change = $diff.changes.find((c) => c.id === changeId);
167→      if (change) {
168→        lines.add(change.location.line);
169→      }
170→    }
171→    return lines;
172→  }
173→);
174→
175→/** Lines that violate tone or WRITING.md bans */
176→export const linesWithSlop = derived(
177→  [editedPlainText, slopMatchers],
178→  ([$text, $matchers]) => {
179→    if (!$text || !$matchers || $matchers.length === 0) return new Set();
180→    const lines = $text.split(/\r?\n/);
181→    const result = new Set();
182→    const compiled = $matchers.map((matcher) => ({
183→      label: matcher.label,
184→      regex: new RegExp(matcher.pattern, matcher.flags),
185→    }));
186→    lines.forEach((line, index) => {
187→      for (const matcher of compiled) {
188→        if (!matcher?.regex) continue;
189→        matcher.regex.lastIndex = 0;
190→        if (matcher.regex.test(line)) {
191→          result.add(index + 1);
192→          break;
193→        }
194→      }
195→    });
196→    return result;
197→  }
198→);
