237→ * @param {string | null} [snapshot.selectedChangeId]
238→ * @param {'annotations' | 'reference'} [snapshot.rightPaneMode]
239→ */
240→export function restoreFromSnapshot(snapshot) {
241→  const restoredFilePath = snapshot.filePath || '';
242→  const restoredFilename =
243→    snapshot.filename || restoredFilePath.split('/').pop() || 'Untitled';
244→  const restoredOriginal = snapshot.originalContent || '';
245→  const restoredEdited = snapshot.editedContent ?? restoredOriginal;
246→  const restoredOriginalPlain = snapshot.originalPlainText || '';
247→  const restoredEditedPlain =
248→    snapshot.editedPlainText || restoredOriginalPlain || '';
249→
250→  /** @type {Map<string, Annotation>} */
251→  const restoredAnnotations = new Map();
252→  if (Array.isArray(snapshot.annotations)) {
253→    for (const entry of snapshot.annotations) {
254→      if (!entry || typeof entry.changeId !== 'string' || !entry.annotation) continue;
255→      restoredAnnotations.set(entry.changeId, entry.annotation);
256→    }
257→  }
258→
259→  previousDiffSnapshot = null;
260→  previousOriginalForSnapshot = restoredOriginalPlain;
261→
262→  filename.set(restoredFilename);
263→  filePath.set(restoredFilePath);
264→  originalContent.set(restoredOriginal);
265→  editedContent.set(restoredEdited);
266→  originalPlainText.set(restoredOriginalPlain);
267→  editedPlainText.set(restoredEditedPlain);
268→  annotations.set(restoredAnnotations);
269→  generalNotes.set(snapshot.generalNotes || '');
270→  startTime.set(snapshot.startedAt ? new Date(snapshot.startedAt) : new Date());
271→  selectedChangeId.set(
272→    typeof snapshot.selectedChangeId === 'string' && snapshot.selectedChangeId.length > 0
273→      ? snapshot.selectedChangeId
274→      : null
275→  );
276→  rightPaneMode.set(snapshot.rightPaneMode === 'reference' ? 'reference' : 'annotations');
277→}
